1	// claim-office.spec.ts
2	import { describe, it, expect } from "vitest";
3	import { quote } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // Quote: empty and basic items
7	  it("quote with empty item list returns premium 5 (processing fee only)", () => {
8	    expect(quote({ yearsWithMHPCO: 0 }, [])).toBe(5);
9	  });
10	  it.todo("quote with a single sword (plain, no modifiers) returns premium 115 (100 base + 10 first insurance + 5 fee)");
11	  it.todo("quote with a single amulet (plain, no modifiers) returns premium 71 (60 base + 6 first insurance + 5 fee)");
12	  it.todo("quote with a single staff (plain, no modifiers) returns premium 93 (80 base + 8 first insurance + 5 fee)");
13	  it.todo("quote with a single potion (plain, no modifiers) returns premium 49 (40 base + 4 first insurance + 5 fee)");
14	
15	  // Quote: multiple items
16	  it.todo("quote with two plain items sums their base premiums (sword + amulet = 100 + 60 = 160 base, +16 first insurance, +5 fee = 181)");
17	
18	  // Components (runes/moonstones)
19	  it.todo("quote with 2 runes returns base premium 50 (2 × 25)");
20	  it.todo("quote with 3 runes applies block discount (60 base premium, not 75)");
21	  it.todo("quote with 4 runes returns 100 (block requires exactly 3, no block applies)");
22	  it.todo("quote with 7 runes returns 175 base premium (one block of 3 + 4 single = 60 + 100)");
23	  it.todo("quote with 2 runes + 1 moonstone returns 75 base premium (no block: different types)");
24	  it.todo("quote with 3 runes + 3 moonstones returns 120 base premium (two separate blocks)");
25	
26	  // Item-specific modifiers
27	  it.todo("quote with cursed sword adds 50% surcharge on item base premium (100 + 50 curse)");
28	  it.todo("quote with sword at enchantment 5 adds 30% surcharge on item base premium");
29	  it.todo("quote with sword at enchantment 4 does not add high-enchantment surcharge");
30	  it.todo("quote with cursed sword at enchantment 5 stacks both surcharges");
31	
32	  // Modifier scope on multi-item policies
33	  it.todo("quote with cursed sword + plain amulet applies curse only to sword's base premium (210 before policy modifiers and fee)");
34	
35	  // Policy-wide modifiers
36	  it.todo("quote with customer at exactly 2 years applies 20% loyalty discount on policy total");
37	  it.todo("quote with customer at less than 2 years does not apply loyalty discount");
38	  it.todo("quote first insurance adds 10% surcharge per item on the policy");
39	  it.todo("quote follow-up contract (after first quote in scenario) applies 15% discount on policy total");
40	
41	  // Rounding
42	  it.todo("premium calculation yielding 197.5 rounds up to 198");
43	
44	  // Integration examples from spec
45	  it.todo("newcomer with cursed sword (steel, enchantment 3, 0 years) returns premium 165");
46	  it.todo("long-standing customer's second contract: cursed sword (enchantment 7, 3 years, 2nd quote) returns premium 160");
47	
48	  // Quote: error cases
49	  it.todo("quote with unknown item type causes CLI to exit non-zero with error to stderr");
50	
51	  // Claim: basic payouts
52	  it.todo("claim on regular sword (steel, enchantment 3) with damage 500 returns payout 400 (full reimbursement minus 100 deductible)");
53	  it.todo("claim on rune (insurance value 250) with damage 200 returns payout 100 (full reimbursement minus 100 deductible)");
54	
55	  // Claim: enchantment threshold
56	  it.todo("claim on steel sword enchantment 9 with damage 1000 returns payout 400 (50% reimbursement, then 100 deductible)");
57	
58	  // Claim: dragon material
59	  it.todo("claim on dragon-material sword enchantment 5 with damage 800 returns payout 700 (full reimbursement, then 100 deductible)");
60	  it.todo("claim on dragon-material sword enchantment 9 with damage 1000 returns payout 400 (50% rule wins, then deductible)");
61	  it.todo("claim on dragon-material sword enchantment 8 with damage 1000 returns payout 400 (high-enchantment clause applies, then deductible)");
62	
63	  // Claim: deductible per damage event
64	  it.todo("claim with two damaged items (sword 500 + amulet 300) applies deductible per item: payout 600");
65	
66	  // Claim: multiple items of the same type
67	  it.todo("policy covering two swords has insurance sum 2000 and cap 4000");
68	  it.todo("claim with two sword damages on a two-sword policy treats each as separate damage with own deductible");
69	  it.todo("claim with more sword damages than swords insured causes CLI to exit non-zero");
70	
71	  // Claim: cap
72	  it.todo("policy with sword + amulet has insurance sum 1600 and cap 3200");
73	  it.todo("policy with sword + 3 runes has insurance sum 1750 (block discount affects premium only, not cap)");
74	  it.todo("cap is based on unmodified insurance value (cursed sword cap = 2000)");
75	  it.todo("first claim of 1500 on sword (cap 2000) returns payout 1400 with remainingCap 600");
76	  it.todo("second claim of 1500 with remainingCap 600 returns payout 600 with remainingCap 0");
77	
78	  // Claim: rounding
79	  it.todo("payout calculation yielding 350.5 rounds down to 350");
80	
81	  // Claim: error cases
82	  it.todo("claim referencing item not in policy causes CLI to exit non-zero with error to stderr");
83	  it.todo("claim with negative damage amount causes CLI to exit non-zero with error to stderr");
84	
85	  // CLI integration
86	  it.todo("CLI reads scenario JSON from stdin and writes results JSON to stdout in step order");
87	});
